#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char N[100005];
        scanf("%s", N);
        int len = strlen(N);
        long long result = 0;
        for (int i = 0; i < len; i++) {
            char temp[100005];
            strcpy(temp, N + i);
            strcat(temp, N);
            strcat(temp, N + i + 1);
            temp[len + i] = '\0';
            for (int j = 0; j < len; j++) {
                result = (result * 10 + temp[j] - '0') % MOD;
            }
        }
        printf("%lld\n", result);
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;
#define MOD 1000000007
int main() {
    int T;
    cin >> T;
    while (T--) {
        string N;
        cin >> N;
        int len = N.length();
        long long result = 0;
        for (int i = 0; i < len; i++) {
            string temp = N.substr(i) + N.substr(0, i);
            for (int j = 0; j < len; j++) {
                result = (result * 10 + temp[j] - '0') % MOD;
            }
        }
        cout << result << endl;
    }
    return 0;
}

