import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String N = sc.next();
            int len = N.length();
            long result = 0;
            for (int i = 0; i < len; i++) {
                String temp = N.substring(i) + N.substring(0, i);
                for (int j = 0; j < len; j++) {
                    result = (result * 10 + temp.charAt(j) - '0') % 1000000007;
                }
            }
            System.out.println(result);
        }
    }
}

