const MOD = 1000000007;
const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readLine = () => lines[idx++];
const readInt = () => parseInt(readLine());
const readString = () => readLine();
const T = readInt();
for (let i = 0; i < T; i++) {
    const N = readString();
    const len_N = N.length;
    let result = 0;
    for (let j = 0; j < len_N; j++) {
        const temp = N.slice(j) + N.slice(0, j);
        for (let k = 0; k < len_N; k++) {
            result = (result * 10 + parseInt(temp[k])) % MOD;
        }
    }
    console.log(result);
}

